Create `Services/IndexedDbStorageService.cs`:
```csharp
namespace SiteInspector.Services;

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

public class IndexedDbStorageService : IStorageService
{
    private readonly IJSRuntime _js;

    public IndexedDbStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbStorage.getAll");
        if (string.IsNullOrEmpty(json)) return new List<Inspection>();
        return JsonSerializer.Deserialize<List<Inspection>>(json) ?? new List<Inspection>();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string>("indexedDbStorage.get", id);
        if (string.IsNullOrEmpty(json)) return null;
        return JsonSerializer.Deserialize<Inspection>(json);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection);
        await _js.InvokeVoidAsync("indexedDbStorage.save", inspection.Id, json);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbStorage.delete", id);
    }

    public async Task<List<Inspection>> GetPendingSyncAsync()
    {
        var all = await GetAllInspectionsAsync();
        return all.Where(i => i.SyncStatus == SyncStatus.Pending && i.Status == InspectionStatus.Completed).ToList();
    }

    public async Task MarkAsSyncedAsync(string id)
    {
        var inspection = await GetInspectionAsync(id);
        if (inspection != null)
        {
            inspection.SyncStatus = SyncStatus.Synced;
            await SaveInspectionAsync(inspection);
        }
    }
}
