@inherits LayoutComponentBase
@inject SyncService SyncService

<div class="app-layout">
    @if (!SyncService.IsOnline)
    {
        <div class="offline-banner">⚡ Offline — changes saved locally</div>
    }
    @Body
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await SyncService.InitializeAsync();
        SyncService.OnConnectivityChanged += OnConnectivityChanged;
    }

    private void OnConnectivityChanged(bool isOnline)
    {
        InvokeAsync(StateHasChanged);
    }
}

@page "/"
@inject IStorageService Storage
@inject NavigationManager Nav

<div class="app-header">
    <h1>🏗️ Site Inspector</h1>
</div>

<div class="page-content">
    @if (_inspections == null)
    {
        <div class="text-center mt-2">
            <div class="loading-spinner"></div>
        </div>
    }
    else if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <div class="icon">📋</div>
            <h2>No Inspections Yet</h2>
            <p>Tap the + button to start a new site inspection</p>
        </div>
    }
    else
    {
        @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
        {
            <div class="card inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                <div class="card-header">
                    <h3>@inspection.SiteName</h3>
                    @if (inspection.SyncStatus == SyncStatus.Synced)
                    {
                        <span class="badge badge-synced">Synced</span>
                    }
                    else if (inspection.Status == InspectionStatus.Completed)
                    {
                        <span class="badge badge-pending">Pending Sync</span>
                    }
                    else
                    {
                        <span class="badge badge-progress">In Progress</span>
                    }
                </div>
                <p class="subtitle">@inspection.InspectorName • @inspection.CreatedAt.ToLocalTime().ToString("MMM d, yyyy h:mm tt")</p>
                <div class="progress-bar">
                    @{ var checked_count = inspection.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked); }
                    <div class="fill" style="width: @(inspection.ChecklistItems.Count > 0 ? (checked_count * 100 / inspection.ChecklistItems.Count) : 0)%"></div>
                </div>
                <small class="text-muted">@checked_count / @inspection.ChecklistItems.Count items checked • @inspection.Photos.Count photos</small>
            </div>
        }
    }
</div>

<button class="fab" @onclick="NewInspection">+</button>

@code {
    private List<Inspection>? _inspections;

    protected override async Task OnInitializedAsync()
    {
        _inspections = await Storage.GetAllInspectionsAsync();
    }

    private void NewInspection()
    {
        Nav.NavigateTo("/new");
    }

    private void OpenInspection(string id)
    {
        Nav.NavigateTo($"/inspect/{id}");
    }
}

@page "/new"
@inject IStorageService Storage
@inject NavigationManager Nav

<div class="app-header">
    <button class="back-btn" @onclick="GoBack">←</button>
    <h1>New Inspection</h1>
</div>

<div class="page-content">
    <div class="card">
        <div class="form-group">
            <label>Site Name</label>
            <input class="form-control" @bind="_siteName" @bind:event="oninput" placeholder="e.g., Building A - Level 3" />
        </div>
        <div class="form-group">
            <label>Inspector Name</label>
            <input class="form-control" @bind="_inspectorName" @bind:event="oninput" placeholder="Your name" />
        </div>
        <button class="btn btn-primary btn-block btn-lg" @onclick="Create" disabled="@(!IsValid)">
            Start Inspection
        </button>
    </div>
</div>

@code {
    private string _siteName = string.Empty;
    private string _inspectorName = string.Empty;

    private bool IsValid => !string.IsNullOrWhiteSpace(_siteName) && !string.IsNullOrWhiteSpace(_inspectorName);

    private async Task Create()
    {
        if (!IsValid) return;

        var inspection = new Inspection
        {
            SiteName = _siteName.Trim(),
            InspectorName = _inspectorName.Trim(),
            ChecklistItems = ChecklistTemplateService.GetDefaultChecklist()
        };

        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspect/{inspection.Id}");
    }

    private void GoBack() => Nav.NavigateTo("/");
}

@page "/inspect/{Id}"
@inject IStorageService Storage
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="app-header">
    <button class="back-btn" @onclick="GoBack">←</button>
    <h1>@(_inspection?.SiteName ?? "Inspection")</h1>
</div>

<div class="tab-bar">
    <button class="@(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>Checklist</button>
    <button class="@(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>Photos (@(_inspection?.Photos.Count ?? 0))</button>
    <button class="@(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>Notes</button>
</div>

<div class="page-content">
    @if (_inspection == null)
    {
        <div class="text-center mt-2"><div class="loading-spinner"></div></div>
    }
    else
    {
        @if (_activeTab == "checklist")
        {
            @foreach (var group in _inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <h3>@group.Key</h3>
                    @foreach (var item in group)
                    {
                        <div class="checklist-item">
                            <span class="item-description">@item.Description</span>
                            <div class="result-buttons">
                                <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)">✓ Pass</button>
                                <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)">✗ Fail</button>
                                <button class="result-btn na @(item.Result == CheckResult.NA ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NA)">N/A</button>
                            </div>
                            @if (item.Result == CheckResult.Fail)
                            {
                                <textarea class="item-notes" placeholder="Note about failure..."
                                          @bind="item.Notes" @bind:event="oninput" @onfocusout="SaveAsync"></textarea>
                            }
                        </div>
                    }
                </div>
            }
        }
        else if (_activeTab == "photos")
        {
            <div class="card">
                <button class="btn btn-outline btn-block" @onclick="CapturePhoto">📷 Take Photo</button>
                <input type="file" id="photo-input" accept="image/*" capture="environment" class="hidden-input" />

                @if (_inspection.Photos.Count > 0)
                {
                    <div class="photo-grid">
                        @foreach (var photo in _inspection.Photos)
                        {
                            <div class="photo-thumb">
                                <img src="@photo.DataUrl" alt="@photo.Caption" />
                                <button class="remove-btn" @onclick="() => RemovePhoto(photo)">×</button>
                            </div>
                        }
                    </div>
                }
                else
                {
                    <p class="text-center text-muted mt-2">No photos yet</p>
                }
            </div>
        }
        else if (_activeTab == "notes")
        {
            <div class="card">
                <div class="form-group">
                    <label>General Notes</label>
                    <textarea class="form-control" @bind="_inspection.Notes" @bind:event="oninput"
                              @onfocusout="SaveAsync" placeholder="Additional observations, concerns, or follow-up items..." rows="6"></textarea>
                </div>
            </div>
        }

        <div class="mt-2">
            @if (_inspection.Status == InspectionStatus.InProgress)
            {
                <button class="btn btn-success btn-block btn-lg" @onclick="CompleteInspection">
                    ✓ Complete Inspection
                </button>
            }
            else
            {
                <div class="card text-center">
                    <p><strong>✓ Inspection Completed</strong></p>
                    <p class="text-muted">@(_inspection.SyncStatus == SyncStatus.Synced ? "Synced to server" : "Waiting to sync...")</p>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string Id { get; set; } = string.Empty;

    private Inspection? _inspection;
    private string _activeTab = "checklist";

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(Id);
        if (_inspection == null)
        {
            Nav.NavigateTo("/");
        }
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        if (_inspection != null)
        {
            await Storage.SaveInspectionAsync(_inspection);
        }
    }

    private async Task CapturePhoto()
    {
        var dataUrl = await JS.InvokeAsync<string?>("cameraHelper.capturePhoto", "photo-input");
        if (!string.IsNullOrEmpty(dataUrl) && _inspection != null)
        {
            _inspection.Photos.Add(new InspectionPhoto
            {
                FileName = $"photo_{_inspection.Photos.Count + 1}.jpg",
                DataUrl = dataUrl,
                Caption = string.Empty
            });
            await SaveAsync();
        }
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection?.Photos.Remove(photo);
        await SaveAsync();
    }

    private async Task CompleteInspection()
    {
        if (_inspection != null)
        {
            _inspection.Status = InspectionStatus.Completed;
            await SaveAsync();
        }
    }

    private void GoBack() => Nav.NavigateTo("/");
}

