+    <h1>@(_inspection?.SiteName ?? "Inspection")</h1>
+</div>
+
+<div class="tab-bar">
+    <button class="@(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>Checklist</button>
+    <button class="@(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>Photos (@(_inspection?.Photos.Count ?? 0))</button>
+    <button class="@(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>Notes</button>
+</div>
+
+<div class="page-content">
+    @if (_inspection == null)
+    {
+        <div class="text-center mt-2"><div class="loading-spinner"></div></div>
+    }
+    else
+    {
+        @if (_activeTab == "checklist")
+        {
+            @foreach (var group in _inspection.ChecklistItems.GroupBy(c => c.Category))
+            {
+                <div class="checklist-category">
+                    <h3>@group.Key</h3>
+                    @foreach (var item in group)
+                    {
+                        <div class="checklist-item">
+                            <span class="item-description">@item.Description</span>
+                            <div class="result-buttons">
+                                <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
+                                        @onclick="() => SetResult(item, CheckResult.Pass)">✓ Pass</button>
+                                <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
+                                        @onclick="() => SetResult(item, CheckResult.Fail)">✗ Fail</button>
+                                <button class="result-btn na @(item.Result == CheckResult.NA ? "selected" : "")"
+                                        @onclick="() => SetResult(item, CheckResult.NA)">N/A</button>
+                            </div>
+                            @if (item.Result == CheckResult.Fail)
+                            {
+                                <textarea class="item-notes" placeholder="Note about failure..."
+                                          @bind="item.Notes" @bind:event="oninput" @onfocusout="SaveAsync"></textarea>
+                            }
+                        </div>
+                    }
+                </div>
+            }
+        }
+        else if (_activeTab == "photos")
+        {
+            <div class="card">
+                <button class="btn btn-outline btn-block" @onclick="CapturePhoto">📷 Take Photo</button>
+                <input type="file" id="photo-input" accept="image/*" capture="environment" class="hidden-input" />
+                
+                @if (_inspection.Photos.Count > 0)
+                {
+                    <div class="photo-grid">
+                        @foreach (var photo in _inspection.Photos)
+                        {
+                            <div class="photo-thumb">
+                                <img src="@photo.DataUrl" alt="@photo.Caption" />
+                                <button class="remove-btn" @onclick="() => RemovePhoto(photo)">×</button>
+                            </div>
+                        }
+                    </div>
+                }
+                else
+                {
+                    <p class="text-center text-muted mt-2">No photos yet</p>
+                }
+            </div>
+        }
+        else if (_activeTab == "notes")
+        {
+            <div class="card">
+                <div class="form-group">
+                    <label>General Notes</label>
+                    <textarea class="form-control" @bind="_inspection.Notes" @bind:event="oninput"
+                              @onfocusout="SaveAsync" placeholder="Additional observations, concerns, or follow-up items..." rows="6"></textarea>
+                </div>
+            </div>
+        }
+
+        <div class="mt-2">
+            @if (_inspection.Status == InspectionStatus.InProgress)
+            {
+                <button class="btn btn-success btn-block btn-lg" @onclick="CompleteInspection">
+                    ✓ Complete Inspection
+                </button>
+            }
+            else
+            {
+                <div class="card text-center">
+                    <p><strong>✓ Inspection Completed</strong></p>
+                    <p class="text-muted">@(_inspection.SyncStatus == SyncStatus.Synced ? "Synced to server" : "Waiting to sync...")</p>
+                </div>
+            }
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter] public string Id { get; set; } = string.Empty;
+
+    private Inspection? _inspection;
+    private string _activeTab = "checklist";
+
+    protected override async Task OnInitializedAsync()
+    {
+        _inspection = await Storage.GetInspectionAsync(Id);
+        if (_inspection == null)
+        {
+            Nav.NavigateTo("/");
+        }
+    }
+
+    private async Task SetResult(ChecklistItem item, CheckResult result)
+    {
+        item.Result = result;
+        await SaveAsync();
+    }
+
+    private async Task SaveAsync()
+    {
+        if (_inspection != null)
+        {
+            await Storage.SaveInspectionAsync(_inspection);
+        }
+    }
+
+    private async Task CapturePhoto()
+    {
+        var dataUrl = await JS.InvokeAsync<string?>("cameraHelper.capturePhoto", "photo-input");
+        if (!string.IsNullOrEmpty(dataUrl) && _inspection != null)
+        {
+            _inspection.Photos.Add(new InspectionPhoto
+            {
+                FileName = $"photo_{_inspection.Photos.Count + 1}.jpg",
+                DataUrl = dataUrl,
+                Caption = string.Empty
+            });
+            await SaveAsync();
+        }
+    }
+
+    private async Task RemovePhoto(InspectionPhoto photo)
+    {
+        _inspection?.Photos.Remove(photo);
+        await SaveAsync();
+    }
+
+    private async Task CompleteInspection()
+    {
+        if (_inspection != null)
+        {
+            _inspection.Status = InspectionStatus.Completed;
+            await SaveAsync();
+        }
+    }
+
+    private void GoBack() => Nav.NavigateTo("/");
+}
